#!/usr/bin/env python3
"""ltx-knot-diffusers.py — Diffusers reference harness for ltx-video.knot.

Cloned from flux-knot-diffusers.py for Phase 1+ of sovereign LTX-Video. The
KNOT remains the source of model weights; diffusers supplies the proven LTX
pipeline math, configs, and module classes (LTXVideoTransformer3DModel,
AutoencoderKLLTXVideo) so we can run SINGLE-BLOCK reference diffs — the method
that cracked FLUX — against native kernels.

Mapping (verbatim+prefix, bijective):
    transformer.<name>  <->  knot key  ltx_dit_<name with . -> _>.bin
    vae.<name>          <->  knot key  ltx_vae_<name with . -> _>.bin

LTX keeps to_q / to_k / to_v separate (no fused qkv), so there is NO tensor
splitting: every diffusers param maps 1:1 to one knot tensor.

This harness deliberately does NOT run a full text-to-video pipeline (it would
OOM on 16 GB and needs the FLUX knot's T5 wired in). It is built to:
  * parse + validate the ltx-video.knot header,
  * load a SINGLE transformer block (or the proj_in / VAE conv) from the knot
    into the matching diffusers submodule, and
  * report tensor coverage so Phase 1 can map native kernels block-by-block.

Usage:
    # Validate the knot + print component/tensor coverage:
    python3 ltx-knot-diffusers.py --knot .../ltx-video.knot --report

    # Load a single transformer block from the knot and diff its forward
    # against a native kernel (Phase 1 entry point):
    python3 ltx-knot-diffusers.py --knot .../ltx-video.knot \
        --load-block transformer:0
"""
from __future__ import annotations

import argparse
import json
import struct
import sys
from dataclasses import dataclass
from pathlib import Path
from typing import Any

REPO = "Lightricks/LTX-Video"

LTX_COMPONENT_PREFIXES = {
    "transformer": ("ltx_dit_",),
    "vae": ("ltx_vae_",),
}
LTX_WEIGHT_COMPONENTS = ("transformer", "vae")
LTX_COMPONENT_POLICY = "ltx-transformer-vae-only (T5 reused from FLUX knot at runtime)"


# ─────────────────────────────────────────────────────────────────────────────
# KNOT reader (identical format to flux-knot-diffusers.py)
# ─────────────────────────────────────────────────────────────────────────────

@dataclass(frozen=True)
class KnotHeader:
    metadata: dict[str, Any]
    payload_offset: int


def read_knot_header(path: Path) -> KnotHeader:
    with path.open("rb") as handle:
        magic = handle.read(4)
        if magic != b"KNOT":
            raise ValueError(f"{path} is not a KNOT file")
        version = struct.unpack("<H", handle.read(2))[0]
        if version != 1:
            raise ValueError(f"{path} has unsupported KNOT version {version}")
        meta_len = struct.unpack("<I", handle.read(4))[0]
        metadata = json.loads(handle.read(meta_len).decode("utf-8"))
    header_len = 10 + meta_len
    padded_header_len = header_len + ((-header_len) % 4)
    return KnotHeader(metadata=metadata, payload_offset=padded_header_len + 1)


def _numel(shape) -> int:
    total = 1
    for dim in shape:
        total *= int(dim)
    return total


def dequantize_q8_0(raw: bytes, shape):
    import numpy as np

    if len(raw) % 34 != 0:
        raise ValueError(f"Q8_0 tensor length must be a multiple of 34, got {len(raw)}")
    blocks = np.frombuffer(raw, dtype=np.uint8).reshape(-1, 34)
    scales = blocks[:, :2].copy().view(np.float16).astype(np.float32).reshape(-1, 1)
    quantized = blocks[:, 2:].copy().view(np.int8).astype(np.float32)
    values = (quantized * scales).reshape(-1)
    return values[: _numel(shape)].reshape(tuple(int(dim) for dim in shape))


class KnotTensorReader:
    def __init__(self, path: Path):
        self.path = path
        header = read_knot_header(path)
        self.metadata = header.metadata
        self.payload_offset = header.payload_offset
        tensors = self.metadata.get("tensors")
        if not isinstance(tensors, dict):
            raise ValueError("KNOT metadata is missing tensor table")
        self.tensors = tensors

    def read_numpy(self, key: str):
        import numpy as np

        info = self.tensors.get(key)
        if not isinstance(info, dict):
            raise KeyError(key)
        shape = info.get("shape")
        if not isinstance(shape, list) or not shape:
            raise ValueError(f"{key} is missing shape metadata")
        offset = int(info["offset"])
        length = int(info["length"])
        tensor_type = str(info.get("type") or "F32")
        with self.path.open("rb") as handle:
            handle.seek(self.payload_offset + offset)
            raw = handle.read(length)
        if len(raw) != length:
            raise ValueError(f"{key} truncated: wanted {length} bytes, got {len(raw)}")
        if tensor_type == "F32":
            return np.frombuffer(raw, dtype="<f4").reshape(tuple(shape))
        if tensor_type == "Q8_0":
            return dequantize_q8_0(raw, shape)
        raise ValueError(f"{key} has unsupported tensor type {tensor_type!r}")


# ─────────────────────────────────────────────────────────────────────────────
# LTX param <-> knot mapping (verbatim + component prefix, bijective)
# ─────────────────────────────────────────────────────────────────────────────

def canonical_to_tensor_key(canonical_name: str) -> str:
    return canonical_name.replace(".", "_") + ".bin"


def ltx_param_to_knot_key(component: str, param_name: str) -> str | None:
    """diffusers submodule param name (relative to the component module) ->
    knot tensor key. LTX is 1:1 (no fused qkv), so this is a pure prefix join."""
    if component not in LTX_WEIGHT_COMPONENTS:
        return None
    return canonical_to_tensor_key(f"ltx_{'dit' if component=='transformer' else 'vae'}.{param_name}")


def validate_ltx_knot_metadata(metadata: dict[str, Any]) -> list[str]:
    config = metadata.get("config")
    config_arch = config.get("arch") if isinstance(config, dict) else None
    arch = metadata.get("arch") or config_arch
    if arch != "ltx":
        return [f"metadata arch must be 'ltx', got {arch!r}"]
    problems: list[str] = []
    tensors = metadata.get("tensors")
    if not isinstance(tensors, dict):
        return ["missing tensor metadata table"]
    names = tuple(tensors.keys())
    for component, prefixes in LTX_COMPONENT_PREFIXES.items():
        if not any(n.startswith(p) for n in names for p in prefixes):
            problems.append(f"missing {component} tensors with prefix {'/'.join(prefixes)}")
    return problems


# ─────────────────────────────────────────────────────────────────────────────
# Reporting + single-block load
# ─────────────────────────────────────────────────────────────────────────────

def report(reader: KnotTensorReader) -> dict[str, Any]:
    cfg = reader.metadata.get("config", {})
    counts = {c: 0 for c in LTX_WEIGHT_COMPONENTS}
    for name in reader.tensors:
        for c, prefixes in LTX_COMPONENT_PREFIXES.items():
            if any(name.startswith(p) for p in prefixes):
                counts[c] += 1
    samples = {}
    for c, prefixes in LTX_COMPONENT_PREFIXES.items():
        picks = []
        for name, info in reader.tensors.items():
            if any(name.startswith(p) for p in prefixes):
                picks.append((name, info.get("type"), info.get("shape")))
            if len(picks) >= 6:
                break
        samples[c] = picks
    return {
        "arch": reader.metadata.get("arch"),
        "config": {k: cfg.get(k) for k in (
            "hidden_dim", "num_layers", "num_heads", "head_dim",
            "cross_attention_dim", "caption_channels", "vae_latent_channels")},
        "tensor_total": len(reader.tensors),
        "component_counts": counts,
        "samples": samples,
        "problems": validate_ltx_knot_metadata(reader.metadata),
    }


def build_empty_ltx_modules(model_dir: Path, *, torch_dtype):
    """Instantiate the diffusers LTX transformer + VAE from config (no weights).
    Returns (transformer, vae). Used for single-block reference diffs."""
    from diffusers import AutoencoderKLLTXVideo, LTXVideoTransformer3DModel

    def _json(p):
        with open(p) as f:
            return json.load(f)

    transformer = LTXVideoTransformer3DModel.from_config(
        _json(model_dir / "transformer" / "config.json"))
    vae = AutoencoderKLLTXVideo.from_config(_json(model_dir / "vae" / "config.json"))
    transformer.to(dtype=torch_dtype)
    vae.to(dtype=torch_dtype)
    return transformer, vae


def resolve_config_model_dir(model: str, *, revision: str, hf_token, local_files_only: bool) -> Path:
    candidate = Path(model).expanduser()
    if candidate.exists():
        if not candidate.is_dir():
            raise ValueError(f"--model path is not a directory: {candidate}")
        return candidate
    from huggingface_hub import snapshot_download
    return Path(snapshot_download(
        model, revision=revision, token=hf_token, local_files_only=local_files_only,
        allow_patterns=["model_index.json", "transformer/config.json", "vae/config.json",
                        "scheduler/*"],
    ))


def load_single_block(reader: KnotTensorReader, component: str, block_index: int,
                      *, model_dir: Path, torch_dtype) -> dict[str, Any]:
    """Load exactly one transformer block's tensors from the knot into the
    matching diffusers submodule. Phase 1 entry point for block-level diffs."""
    import torch

    transformer, vae = build_empty_ltx_modules(model_dir, torch_dtype=torch_dtype)
    if component == "transformer":
        module = transformer.transformer_blocks[block_index]
        prefix_in_module = f"transformer_blocks.{block_index}."
    elif component == "vae":
        raise NotImplementedError("VAE single-block load: address by submodule path")
    else:
        raise ValueError(component)

    loaded, missing = 0, []
    with torch.no_grad():
        for pname, dest in module.state_dict().items():
            full = prefix_in_module + pname
            key = ltx_param_to_knot_key(component, full)
            if key is None or key not in reader.tensors:
                missing.append(full)
                continue
            arr = reader.read_numpy(key)
            t = torch.from_numpy(arr.copy()).to(dtype=dest.dtype, device=dest.device)
            dest.copy_(t.reshape(dest.shape))
            loaded += 1
    return {"component": component, "block_index": block_index,
            "loaded": loaded, "missing": missing}


def _det(seed: int, n: int):
    """Deterministic synthetic input — mirrors the Rust `det(seed,n)` convention
    (open-source/gnosis/distributed-inference/src/model_ltx_dit.rs) so the
    diffusers reference and the native dump consume byte-identical inputs."""
    import numpy as np

    i = np.arange(1, n + 1, dtype=np.float64)
    a = i * 0.0007 + seed * 0.013
    return ((np.sin(a) * 0.8 + np.cos(a * 2.3) * 0.2) * 0.5).astype(np.float32)


def dump_block(reader: "KnotTensorReader", block_index: int, *, model_dir: Path,
               torch_dtype, frames: int, height: int, width: int, cap_len: int,
               out_prefix: str) -> dict[str, Any]:
    """Run ONE diffusers LTXVideoTransformerBlock (weights from the knot) on the
    fixed deterministic input and dump its output hidden states to <prefix>.bin +
    <prefix>.json (flat little-endian f32). Phase-1 numeric reference, matching
    the native ltx-block0-dump bin.

    Inputs (synthetic, no T5/VAE): hidden=det(1) [1,F*H*W,2048], encoder=det(2)
    [1,cap_len,2048] (already projection-space), temb=det(3) [1,1,6*2048] (broadcast
    over tokens), 3D RoPE over (F,H,W) frame-major with rope_interpolation_scale=None.
    """
    import json as _json

    import numpy as np
    import torch
    from diffusers.models.transformers.transformer_ltx import (
        LTXVideoRotaryPosEmbed,
        LTXVideoTransformerBlock,
    )

    cfg = {}
    cfg_path = model_dir / "transformer" / "config.json"
    if cfg_path.exists():
        with open(cfg_path) as f:
            cfg = _json.load(f)
    hidden = int(cfg.get("num_attention_heads", 32)) * int(cfg.get("attention_head_dim", 64))
    heads = int(cfg.get("num_attention_heads", 32))
    head_dim = int(cfg.get("attention_head_dim", 64))
    cross = int(cfg.get("cross_attention_dim", 2048))

    block = LTXVideoTransformerBlock(
        dim=hidden, num_attention_heads=heads, attention_head_dim=head_dim,
        cross_attention_dim=cross, qk_norm="rms_norm_across_heads",
        activation_fn="gelu-approximate", eps=1e-6, elementwise_affine=False,
    ).to(dtype=torch_dtype).eval()

    prefix = f"transformer_blocks.{block_index}."
    loaded, missing = 0, []
    with torch.no_grad():
        for pname, dest in block.state_dict().items():
            key = ltx_param_to_knot_key("transformer", prefix + pname)
            if key is None or key not in reader.tensors:
                missing.append(pname)
                continue
            arr = reader.read_numpy(key)
            dest.copy_(torch.from_numpy(arr.reshape(tuple(dest.shape)).copy()).to(torch_dtype))
            loaded += 1
    if missing:
        return {"loaded": loaded, "missing": missing}

    img_len = frames * height * width
    img = torch.from_numpy(_det(1, img_len * hidden).reshape(1, img_len, hidden)).to(torch_dtype)
    enc = torch.from_numpy(_det(2, cap_len * hidden).reshape(1, cap_len, hidden)).to(torch_dtype)
    temb = torch.from_numpy(_det(3, 6 * hidden).reshape(1, 1, 6 * hidden)).to(torch_dtype)
    rope = LTXVideoRotaryPosEmbed(dim=hidden, base_num_frames=20, base_height=2048,
                                  base_width=2048, patch_size=1, patch_size_t=1, theta=10000.0)
    with torch.no_grad():
        image_rotary_emb = rope(img, num_frames=frames, height=height, width=width,
                                rope_interpolation_scale=None, video_coords=None)
        out = block(hidden_states=img, encoder_hidden_states=enc, temb=temb,
                    image_rotary_emb=image_rotary_emb, encoder_attention_mask=None)
    block_out = out[0].cpu().numpy().reshape(-1).astype(np.float32)

    Path(out_prefix + ".bin").write_bytes(block_out.tobytes())
    Path(out_prefix + ".json").write_text(_json.dumps(
        {"h": hidden, "F": frames, "H": height, "W": width, "img_len": img_len,
         "cap_len": cap_len, "fields": {"block_out": {"offset": 0, "len": int(block_out.size)}}},
        indent=2))
    return {"loaded": loaded, "missing": [], "out_prefix": out_prefix,
            "block_out_len": int(block_out.size),
            "stats": {"mean": float(block_out.mean()), "std": float(block_out.std())}}


def _det_latent(seed: int, c: int, f: int, h: int, w: int):
    """Deterministic latent matching model_ltx_vae.rs `det(7,...)` (NCDHW flat)."""
    import numpy as np

    n = c * f * h * w
    flat = _det(seed, n)
    return flat.reshape(1, c, f, h, w)


def dump_vae_decode(reader: "KnotTensorReader", *, model_dir: Path, torch_dtype,
                    frames: int, height: int, width: int, out_prefix: str) -> dict[str, Any]:
    """Load the FULL AutoencoderKLLTXVideo decoder from the knot and decode the
    SAME fixed deterministic latent (seed 7) as the native ltx-vae-dump bin, then
    dump RGB NCDHW f32 to <prefix>.bin. Phase-3 numeric reference (cos≈1.0 target).

    The diffusers VAE expects the per-channel-normalized latent and un-normalizes
    internally via latents_mean/std; the native decoder mirrors that. We pass the
    raw seed-7 latent to BOTH so the comparison is apples-to-apples.
    """
    import numpy as np
    import torch

    _, vae = build_empty_ltx_modules(model_dir, torch_dtype=torch_dtype)
    # Load all vae.* tensors from the knot into the diffusers VAE.
    loaded, missing = 0, []
    with torch.no_grad():
        for pname, dest in vae.state_dict().items():
            key = ltx_param_to_knot_key("vae", pname)
            if key is None or key not in reader.tensors:
                missing.append(pname)
                continue
            arr = reader.read_numpy(key)
            t = torch.from_numpy(arr.copy()).to(dtype=dest.dtype, device=dest.device)
            dest.copy_(t.reshape(dest.shape))
            loaded += 1
    c = int(vae.config.latent_channels)
    latent = torch.from_numpy(_det_latent(7, c, frames, height, width)).to(dtype=torch_dtype)
    with torch.no_grad():
        # AutoencoderKLLTXVideo.decode handles un-normalization + temporal tiling.
        out = vae.decode(latent, return_dict=False)[0]
    rgb = out.float().cpu().numpy().reshape(-1)
    Path(out_prefix + ".bin").write_bytes(rgb.astype(np.float32).tobytes())
    Path(out_prefix + ".json").write_text(json.dumps({
        "shape": list(out.shape), "len": int(rgb.size),
        "loaded": loaded, "missing": len(missing)}, indent=2))
    return {"loaded": loaded, "missing": missing[:20], "missing_count": len(missing),
            "shape": list(out.shape), "out_prefix": out_prefix}


def main() -> int:
    ap = argparse.ArgumentParser(description="Diffusers reference harness for ltx-video.knot")
    ap.add_argument("--knot", required=True, type=Path)
    ap.add_argument("--model", default=REPO,
                    help="LTX repo id or local dir for configs only (no weights)")
    ap.add_argument("--report", action="store_true", help="print knot coverage report and exit")
    ap.add_argument("--load-block", help="component:index e.g. transformer:0")
    ap.add_argument("--dump-block", type=int, default=None,
                    help="run diffusers transformer block N on the fixed deterministic "
                         "input and dump output hidden states (Phase-1 numeric reference)")
    ap.add_argument("--dump-vae-decode", action="store_true",
                    help="load the full VAE decoder from the knot and decode the "
                         "fixed deterministic seed-7 latent (Phase-3 numeric reference)")
    ap.add_argument("--out-prefix", default="/tmp/ltx-phase1/ref-block0")
    ap.add_argument("--frames", type=int, default=2)
    ap.add_argument("--height", type=int, default=2)
    ap.add_argument("--width", type=int, default=2)
    ap.add_argument("--cap-len", type=int, default=3)
    ap.add_argument("--dtype", default="fp32")
    ap.add_argument("--revision", default="main")
    ap.add_argument("--hf-token", default=None)
    ap.add_argument("--local-files-only", action="store_true")
    args = ap.parse_args()

    reader = KnotTensorReader(args.knot)
    problems = validate_ltx_knot_metadata(reader.metadata)
    if problems:
        print("LTX KNOT validation problems: " + "; ".join(problems), file=sys.stderr)

    if args.dump_vae_decode:
        import torch
        dtype = {"fp32": torch.float32, "fp16": torch.float16, "bf16": torch.bfloat16}[args.dtype]
        model_dir = resolve_config_model_dir(
            args.model, revision=args.revision, hf_token=args.hf_token,
            local_files_only=args.local_files_only)
        result = dump_vae_decode(reader, model_dir=model_dir, torch_dtype=dtype,
                                 frames=args.frames, height=args.height, width=args.width,
                                 out_prefix=args.out_prefix)
        print(json.dumps(result, indent=2))
        return 0 if not result.get("missing_count") else 1

    if args.dump_block is not None:
        import torch
        dtype = {"fp32": torch.float32, "fp16": torch.float16, "bf16": torch.bfloat16}[args.dtype]
        model_dir = resolve_config_model_dir(
            args.model, revision=args.revision, hf_token=args.hf_token,
            local_files_only=args.local_files_only)
        result = dump_block(reader, args.dump_block, model_dir=model_dir,
                            torch_dtype=dtype, frames=args.frames, height=args.height,
                            width=args.width, cap_len=args.cap_len, out_prefix=args.out_prefix)
        print(json.dumps(result, indent=2))
        return 0 if not result.get("missing") else 1

    if args.report or not args.load_block:
        print(json.dumps(report(reader), indent=2))
        return 0 if not problems else 1

    component, idx = args.load_block.split(":")
    import torch
    dtype = {"fp32": torch.float32, "fp16": torch.float16, "bf16": torch.bfloat16}[args.dtype]
    model_dir = resolve_config_model_dir(
        args.model, revision=args.revision, hf_token=args.hf_token,
        local_files_only=args.local_files_only)
    result = load_single_block(reader, component, int(idx),
                               model_dir=model_dir, torch_dtype=dtype)
    print(json.dumps(result, indent=2))
    if result["missing"]:
        print(f"WARNING: {len(result['missing'])} params not found in knot", file=sys.stderr)
        return 1
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
